mapper.select:
SELECT DATE_FORMAT(v.voucher_date, '%Y-%m') AS statMonth, v.project_id AS projectId, COUNT(v.id) AS totalVouchers, SUM(CASE WHEN v.status = 0 THEN 1 ELSE 0 END) AS pendingVouchers, SUM(CASE WHEN v.status = 1 THEN 1 ELSE 0 END) AS approvedVouchers, SUM(CASE WHEN v.status = 2 THEN 1 ELSE 0 END) AS uploadedVouchers, SUM(v.total_debit) AS totalDebit, SUM(v.total_credit) AS totalCredit FROM fin_voucher v WHERE v.is_deleted = 0 AND v.voucher_date IS NOT NULL
AND v.project_id IN #{id}
AND 1=0
AND v.project_id = #{projectId}
AND DATE_FORMAT(v.voucher_date, '%Y-%m') >= #{startMonth}
AND DATE_FORMAT(v.voucher_date, '%Y-%m') <= #{endMonth}
GROUP BY DATE_FORMAT(v.voucher_date, '%Y-%m'), v.project_id ORDER BY statMonth, v.project_id
